import java.io.File
import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Paths, StandardOpenOption}
import java.nio.file.Files

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {
  private val baseDirectory = "uploads"
  
  def serveFile(filename: String) = Action {
    try {
      val canonicalBase = new File(baseDirectory).getCanonicalFile
      val requestedFile = new File(baseDirectory, filename)
      val canonicalRequested = requestedFile.getCanonicalFile
      
      if (canonicalRequested.getParentFile != canonicalBase) {
        return NotFound("File not found")
      }
      
      if (!canonicalRequested.getAbsolutePath.startsWith(canonicalBase.getAbsolutePath)) {
        return NotFound("File not found")
      }
      
      if (!Files.exists(canonicalRequested.toPath)) {
        return NotFound("File not found")
      }
      
      val fileContent = Source.fromFile(canonicalRequested).mkString
      Ok(fileContent).as("text/plain")
    } catch {
      case _: Exception => NotFound("File not found")
    }
  }
}